) as v(contact_id, email, origine, type, texte)
left join public.members mm on mm.email = v.email::text
where not exists (select 1 from public.comments x
  where x.contact_id = v.contact_id and x.texte = v.texte
    and x.author_id is not distinct from mm.id);
